const redis = $json;
const request = $('Webhook').first().json;

const requestedVersion =
  request.params?.version ||
  request.query?.version ||
  request.body?.version ||
  request.version ||
  null;

const rawValue =
  redis.value ??
  redis.propertyName ??
  redis.data ??
  redis.message ??
  redis.redisValue ??
  redis.technicalReadme ??
  redis.content ??
  redis.result ??
  null;

let parsed = null;

if (typeof rawValue === 'string') {
  try {
    parsed = JSON.parse(rawValue);
  } catch {
    parsed = null;
  }
} else if (rawValue && typeof rawValue === 'object') {
  parsed = rawValue;
}

const technicalReadme =
  parsed?.technicalReadme ??
  (rawValue === null || rawValue === undefined ? null : String(rawValue));

return {
  json: {
    ok: Boolean(technicalReadme),
    requestedVersion: requestedVersion ? String(requestedVersion) : null,
    releaseVersion: String(
      parsed?.releaseVersion ||
      requestedVersion ||
      'sin-version'
    ),
    generatedAt: parsed?.generatedAt || null,
    technicalReadme,
  },
};

const {
  ok,
  requestedVersion,
  releaseVersion,
  generatedAt,
  technicalReadme,
} = $json;

function escapeHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function formatDisplayDate(value) {
  if (!value) return null;

  const date = new Date(String(value));

  if (Number.isNaN(date.getTime())) {
    return String(value);
  }

  return new Intl.DateTimeFormat('es-AR', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
    timeZone: 'America/Argentina/Buenos_Aires',
  }).format(date);
}

const title = 'Release JSAT ' + releaseVersion;
const subtitle = generatedAt
  ? 'Generado el ' + formatDisplayDate(generatedAt)
  : 'README recuperado desde Redis';

const markdownLiteral = JSON.stringify(String(technicalReadme || ''))
  .replace(/</g, '\\u003C')
  .replace(/>/g, '\\u003E')
  .replace(/&/g, '\\u0026');

const html = ok
  ? `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>${escapeHtml(title)}</title>

  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Roboto:wght@400;500;700;800&display=swap" rel="stylesheet">
  <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/github-markdown-css/5.5.0/github-markdown.min.css">
  <script src="https://cdn.jsdelivr.net/npm/marked/marked.min.js"></script>

  <style>
    :root {
      --page-bg: #edf4fc;
      --surface: #ffffff;
      --surface-soft: #f8fafc;
      --text: #0f172a;
      --muted: #64748b;
      --border: #dbe3ee;
      --accent: #1d4ed8;
      --accent-soft: #dbeafe;
    }

    * { box-sizing: border-box; }

    body {
      max-width: 1180px;
      min-width: 280px;
      margin: 0 auto;
      padding: 32px 24px;
      background:
        radial-gradient(circle at top right, rgba(37, 99, 235, .10), transparent 32%),
        var(--page-bg);
      color: var(--text);
      font-family: Roboto, Arial, sans-serif;
    }

    .shell {
      overflow: visible;
      border: 1px solid var(--border);
      border-radius: 18px;
      background: var(--surface);
      box-shadow: 0 16px 42px rgba(15, 23, 42, .10);
    }

    .hero {
      position: sticky;
      top: 0;
      z-index: 20;
      overflow: hidden;
      padding: 24px 32px 22px;
      border-radius: 17px 17px 0 0;
      background: linear-gradient(115deg, #0f172a 0%, #172554 52%, #1e40af 100%);
      color: #fff;
      box-shadow: 0 8px 18px rgba(15, 23, 42, .18);
    }

    .hero::after {
      position: absolute;
      top: -120px;
      right: -80px;
      width: 310px;
      height: 310px;
      border: 1px solid rgba(255,255,255,.15);
      border-radius: 50%;
      content: "";
      box-shadow: 0 0 0 38px rgba(255,255,255,.035), 0 0 0 76px rgba(255,255,255,.025);
    }

    .hero-content { position: relative; z-index: 1; }

    .hero h1 {
      margin: 0;
      color: #fff;
      font-size: 30px;
      font-weight: 800;
      letter-spacing: -.025em;
      line-height: 1.15;
    }

    .hero p {
      margin: 10px 0 0;
      color: rgba(255,255,255,.80);
      font-size: 14px;
    }

    .markdown-body {
      max-width: none;
      margin: 0;
      padding: 32px;
      background: var(--surface);
      color: var(--text) !important;
      font-family: Roboto, Arial, sans-serif;
      font-size: 15px;
      line-height: 1.65;
    }

    .markdown-body,
    .markdown-body p,
    .markdown-body li,
    .markdown-body ul,
    .markdown-body ol,
    .markdown-body strong,
    .markdown-body em,
    .markdown-body span,
    .markdown-body code { color: var(--text) !important; }

    .markdown-body h1,
    .markdown-body h2,
    .markdown-body h3,
    .markdown-body h4,
    .markdown-body h5,
    .markdown-body h6 {
      color: #0b1220 !important;
      font-family: Roboto, Arial, sans-serif;
    }

    .markdown-body h1 {
      padding-bottom: 12px;
      border-bottom: 1px solid var(--border);
      font-size: 25px;
    }

    .markdown-body h2 {
      margin-top: 34px;
      padding-bottom: 9px;
      border-bottom: 1px solid #e2e8f0;
      font-size: 21px;
    }

    .markdown-body h3 { font-size: 17px; }
    .markdown-body a { color: #1d4ed8 !important; }
    .markdown-body hr { border-color: var(--border) !important; }
    .markdown-body pre, .markdown-body code { background: #f8fafc !important; }

    .search-bar {
      display: flex;
      align-items: center;
      gap: 10px;
      max-width: 620px;
      margin-top: 16px;
      padding: 10px 12px;
      border: 1px solid rgba(191, 219, 254, .88);
      border-radius: 10px;
      background: rgba(255, 255, 255, .97);
      box-shadow: 0 4px 12px rgba(15, 23, 42, .12);
    }

    .search-bar[hidden] {
      display: none;
    }

    .search-icon {
      color: var(--accent);
      font-size: 18px;
      font-weight: 800;
      line-height: 1;
    }

    .search-input {
      width: 100%;
      min-width: 0;
      border: 0;
      outline: 0;
      background: transparent;
      color: var(--text);
      font: 500 14px/1.4 Roboto, Arial, sans-serif;
    }

    .search-input::placeholder { color: #64748b; }

    .search-count {
      display: none;
      flex: 0 0 auto;
      color: #475569;
      font-size: 12px;
      font-weight: 700;
      white-space: nowrap;
    }

    .detail-section { margin-top: 24px; }
    .detail-section > :first-child { margin-top: 0; }

    .ticket-list {
      display: grid;
      gap: 12px;
      margin-top: 16px;
    }

    .ticket-card {
      overflow: hidden;
      border: 1px solid var(--border);
      border-radius: 13px;
      background: var(--surface);
      box-shadow: 0 4px 14px rgba(15,23,42,.045);
    }

    .ticket-card > summary {
      display: flex;
      align-items: center;
      gap: 10px;
      min-height: 56px;
      padding: 12px 15px;
      cursor: pointer;
      list-style: none;
      user-select: none;
    }

    .ticket-card > summary::-webkit-details-marker { display: none; }

    .ticket-card > summary::after {
      flex: 0 0 auto;
      width: 9px;
      height: 9px;
      margin: 0 5px 4px auto;
      border-right: 2px solid var(--accent);
      border-bottom: 2px solid var(--accent);
      background: transparent;
      content: "";
      transform: rotate(45deg);
      transition: transform .18s ease;
    }

    .ticket-card[open] > summary {
      border-bottom: 1px solid var(--border);
    }

    .ticket-card[open] > summary::after {
      margin-top: 5px;
      margin-bottom: 0;
      transform: rotate(225deg);
    }

    .ticket-card.sis-card > summary,
    .ticket-card.rec-card > summary {
      background: linear-gradient(90deg, #eff6ff, #fff);
    }

    .ticket-code {
      flex: 0 0 auto;
      padding: 5px 9px;
      border-radius: 999px;
      font-size: 12px;
      font-weight: 800;
      letter-spacing: .02em;
      line-height: 1;
    }

    .sis-card .ticket-code,
    .rec-card .ticket-code {
      background: var(--accent-soft);
      color: var(--accent) !important;
    }

    .ticket-title {
      min-width: 0;
      color: #1e293b !important;
      font-size: 14px;
      font-weight: 700;
    }

    .ticket-content {
      padding: 18px;
      background: #fff;
    }

    .ticket-content > :first-child { margin-top: 0; }
    .ticket-content > :last-child { margin-bottom: 0; }

    .empty-filter {
      display: none;
      margin-top: 14px;
      padding: 16px;
      border: 1px dashed #cbd5e1;
      border-radius: 10px;
      color: var(--muted);
      background: var(--surface-soft);
      font-size: 14px;
    }

    @media (max-width: 767px) {
      body { padding: 12px; }
      .hero { padding: 18px 20px; }
      .hero h1 { font-size: 25px; }
      .search-bar { margin-top: 14px; }
      .markdown-body { padding: 22px 18px; }
      .ticket-card > summary { min-height: 52px; padding: 11px 12px; }
      .ticket-content { padding: 14px; }
    }
  </style>
</head>
<body>
  <main class="shell">
    <header class="hero">
      <div class="hero-content">
        <h1>${escapeHtml(title)}</h1>
        <p>${escapeHtml(subtitle)}</p>

        <div id="header-search" class="search-bar" hidden>
          <span class="search-icon" aria-hidden="true">⌕</span>
          <input
            id="ticket-search"
            class="search-input"
            type="search"
            autocomplete="off"
            placeholder="Buscar por SIS, REC, título o contenido"
          >
          <span id="search-count" class="search-count"></span>
        </div>
      </div>
    </header>

    <article id="content" class="markdown-body"></article>
  </main>

  <script>
    const markdown = ${markdownLiteral};

    function getHeadingLevel(element) {
      if (!element || !/^H[1-6]$/.test(element.tagName)) {
        return null;
      }

      return Number(element.tagName.substring(1));
    }

    function isHeading(element) {
      return Boolean(
        element &&
        element.nodeType === Node.ELEMENT_NODE &&
        /^H[1-6]$/.test(element.tagName)
      );
    }

    function getSectionType(element) {
      if (!isHeading(element)) {
        return null;
      }

      const text = String(element.textContent || '').trim();
      const match = text.match(/Cambios detallados por\\s+(SIS|REC)\\b/i);

      return match ? match[1].toUpperCase() : null;
    }

    function getTicket(element, expectedType) {
      if (!isHeading(element)) {
        return null;
      }

      const text = String(element.textContent || '').trim();
      const expression = expectedType === 'SIS'
        ? /\\b(SIS-\\d+)\\b/i
        : /\\b(REC-\\d+)\\b/i;

      const match = text.match(expression);

      if (!match) {
        return null;
      }

      return {
        code: match[1].toUpperCase(),
        title: text
          .replace(expression, '')
          .replace(/^[\\s:—–-]+/, '')
          .replace(/[\\s:—–-]+$/, '')
          .trim(),
      };
    }

    function findSectionEnd(sectionHeading, sectionType) {
      const sectionLevel = getHeadingLevel(sectionHeading);
      let node = sectionHeading.nextElementSibling;

      while (node) {
        if (isHeading(node)) {
          const nextSectionType = getSectionType(node);
          const ticket = getTicket(node, sectionType);
          const nodeLevel = getHeadingLevel(node);

          if (nextSectionType) {
            return node;
          }

          /*
           * Un heading del mismo nivel o superior cierra la sección,
           * salvo que sea otro ticket del tipo esperado.
           */
          if (!ticket && nodeLevel <= sectionLevel) {
            return node;
          }
        }

        node = node.nextElementSibling;
      }

      return null;
    }

    function createTicketCard(heading, ticket, sectionType, stopNode) {
      const card = document.createElement('details');
      const summary = document.createElement('summary');
      const code = document.createElement('span');
      const title = document.createElement('span');
      const body = document.createElement('div');

      card.className = 'ticket-card ' + sectionType.toLowerCase() + '-card';
      code.className = 'ticket-code';
      title.className = 'ticket-title';
      body.className = 'ticket-content';

      code.textContent = ticket.code;
      title.textContent = ticket.title || (
        sectionType === 'REC'
          ? 'Detalle del requerimiento'
          : 'Detalle técnico'
      );

      summary.appendChild(code);
      summary.appendChild(title);
      card.appendChild(summary);
      card.appendChild(body);

      const nodesToMove = [];
      let node = heading.nextSibling;

      while (node && node !== stopNode) {
        const nextNode = node.nextSibling;

        if (isHeading(node) && getTicket(node, sectionType)) {
          break;
        }

        nodesToMove.push(node);
        node = nextNode;
      }

      heading.replaceWith(card);

      nodesToMove.forEach(function(item) {
        body.appendChild(item);
      });

      card.dataset.search = [
        ticket.code,
        ticket.title,
        body.textContent,
      ].join(' ').toLowerCase();
    }

    function enhanceDetailSection(sectionHeading, sectionType) {
      const sectionEnd = findSectionEnd(sectionHeading, sectionType);
      const tickets = [];
      let node = sectionHeading.nextElementSibling;

      while (node && node !== sectionEnd) {
        const ticket = getTicket(node, sectionType);

        if (ticket) {
          tickets.push({
            heading: node,
            ticket: ticket,
          });
        }

        node = node.nextElementSibling;
      }

      tickets.forEach(function(item, index) {
        const nextTicket = tickets[index + 1];
        const stopNode = nextTicket ? nextTicket.heading : sectionEnd;

        createTicketCard(
          item.heading,
          item.ticket,
          sectionType,
          stopNode
        );
      });
    }

    function addSearch(content) {
      const cards = Array.from(content.querySelectorAll('.ticket-card'));
      const search = document.getElementById('header-search');

      if (!cards.length) {
        search.hidden = true;
        return;
      }

      search.hidden = false;

      const empty = document.createElement('div');
      empty.className = 'empty-filter';
      empty.id = 'empty-filter';
      empty.textContent = 'No hay SIS ni REC que coincidan con la búsqueda.';
      content.insertBefore(empty, content.firstChild);

      const input = document.getElementById('ticket-search');
      const count = document.getElementById('search-count');

      input.addEventListener('input', function() {
        const query = String(input.value || '').trim().toLowerCase();
        let visible = 0;

        cards.forEach(function(card) {
          const matches = !query || card.dataset.search.indexOf(query) !== -1;
          card.style.display = matches ? '' : 'none';

          if (matches) {
            visible += 1;
          }
        });

        empty.style.display = query && visible === 0 ? 'block' : 'none';
        count.style.display = query ? 'inline' : 'none';
        count.textContent = visible + ' resultado' + (visible === 1 ? '' : 's');
      });
    }
    const content = document.getElementById('content');

    if (typeof marked === 'undefined') {
      content.innerHTML = '<p>No se pudo cargar el renderizador de Markdown.</p>';
    } else {
      content.innerHTML = marked.parse(markdown);

      /*
       * Solo se crean cards dentro de “Cambios detallados por SIS”
       * y “Cambios detallados por REC”. Así nunca se mezclan ni se
       * anidan entre sí.
       */
      const detailSections = Array.from(
        content.querySelectorAll('h1, h2, h3, h4, h5, h6')
      );

      detailSections.forEach(function(heading) {
        const type = getSectionType(heading);

        if (type) {
          enhanceDetailSection(heading, type);
        }
      });

      addSearch(content);
    }
  </script>
</body>
</html>`
  : `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Release no encontrada</title>
  <style>
    body { margin: 0; padding: 32px; background: #eef4fc; color: #0f172a; font: 16px Roboto, Arial, sans-serif; }
    .card { max-width: 720px; margin: 0 auto; padding: 28px; border: 1px solid #dbe3ee; border-radius: 16px; background: #fff; box-shadow: 0 12px 30px rgba(15,23,42,.08); }
    h1 { margin-top: 0; }
    p { color: #475569; }
    code { padding: 3px 7px; border-radius: 6px; background: #eff6ff; color: #1d4ed8; }
  </style>
</head>
<body>
  <div class="card">
    <h1>Release no encontrada</h1>
    <p>No se encontró contenido en Redis para la versión <code>${escapeHtml(releaseVersion)}</code>.</p>
  </div>
</body>
</html>`;

return {
  json: {
    ok: Boolean(ok),
    requestedVersion,
    releaseVersion,
    generatedAt,
    technicalReadme,
    html,
  },
};
